#!/usr/bin/env python3
import pygame
import sys
import time
import math
import random
import base64
import io

# ====================== COMMAND-LINE PARSING ======================
binary_mode = False
misere_mode = False
pile_args = []
for arg in sys.argv[1:]:
    if arg in ('--binary', '-b'):
        binary_mode = True
    elif arg in ('--misere', '-m'):
        misere_mode = True
    else:
        pile_args.append(arg)

if len(pile_args) not in (0, 3):
    print("Error: Provide either 0 arguments or exactly three non-negative integers for the pile sizes.", file=sys.stderr)
    sys.exit(1)

if len(pile_args) == 3:
    try:
        piles = [int(x) for x in pile_args]
        if any(p < 0 for p in piles):
            raise ValueError("Negative pile size")
    except (ValueError, TypeError):
        print("Error: Pile sizes must be non-negative integers.", file=sys.stderr)
        sys.exit(1)
    custom_start = True
else:
    custom_start = False

# ====================== EMBEDDED SOUNDS ======================
# === PASTE YOUR REAL BASE64 STRINGS HERE (run the command below) ===
APPLAUSE_B64 = """"""
BOOING_B64 = """"""
# =================================================================
pygame.mixer.pre_init(44100, -16, 2, 512)
pygame.init()
pygame.mixer.init()

applause_sound = None
booing_sound = None
if APPLAUSE_B64 and "PASTE" not in APPLAUSE_B64:
    try:
        applause_sound = pygame.mixer.Sound(io.BytesIO(base64.b64decode(APPLAUSE_B64)))
        print("✅ Applause loaded")
    except Exception as e:
        print(f"⚠️ Applause failed: {e}")
if BOOING_B64 and "PASTE" not in BOOING_B64:
    try:
        booing_sound = pygame.mixer.Sound(io.BytesIO(base64.b64decode(BOOING_B64)))
        print("✅ Booing loaded")
    except Exception as e:
        print(f"⚠️ Booing failed: {e}")

# ====================== DISPLAY ======================
info = pygame.display.Info()
WIDTH = info.current_w
HEIGHT = info.current_h
screen = pygame.display.set_mode((WIDTH, HEIGHT), pygame.FULLSCREEN)
pygame.display.set_caption("Nim Game - Version 1.6.4")

BG_COLOR = (15, 15, 25)
TEXT_COLOR = (240, 240, 255)
STONE_WIN = (100, 255, 100)
STONE_LOSS = (255, 100, 100)
STONE_NEUTRAL = (128, 128, 150)
MSG_COLOR = (150, 200, 255)
BUTTON_COLOR = (50, 150, 50)
BUTTON_TEXT_COLOR = (255, 255, 255)

base_w, base_h = 1600, 1200
s = min(WIDTH / base_w, HEIGHT / base_h)

font_size = int(72 * s)
small_font_size = int(48 * s)
font = pygame.font.SysFont(None, font_size)
small_font = pygame.font.SysFont(None, small_font_size)

STONES_RADIUS = int(30 * s)
STONES_SPACING = int(80 * s)
HALF_SPACING = STONES_SPACING // 2

PILE_CENTER_X = WIDTH // 2
PILE_STONES_YS = [int(y * s) for y in [280, 590, 900]]

title_y = int(40 * s)
label_y_offset = int(-90 * s)
binary_y_offset = int(80 * s)
mode_display_y = title_y + font_size + int(30 * s)
hint_y = HEIGHT - int(120 * s * 0.95) - int(50 * s)

button_width = int(320 * s * 0.95)
button_height = int(120 * s * 0.95)
button_spacing = int(40 * s)
border_width = int(6 * s)

# Rects
hint_rect         = pygame.Rect(0, hint_y, button_width, button_height)
mode_rect         = pygame.Rect(0, hint_y, button_width, button_height)
instructions_rect = pygame.Rect(0, hint_y, button_width, button_height)
restart_rect      = pygame.Rect(0, hint_y, button_width, button_height)
exit_rect         = pygame.Rect(0, hint_y, button_width, button_height)
undo_rect         = pygame.Rect(0, hint_y, button_width, button_height)
instr_exit_rect   = pygame.Rect(0, HEIGHT - button_height, int(280 * s), button_height)

# Message position (needed for win/loss text)
pile1_label_y = PILE_STONES_YS[0] + label_y_offset
message_y = (title_y + pile1_label_y) // 2

# ====================== PERFECTLY CENTERED BUTTON HELPER ======================
def draw_button(rect, text, bg_color=BUTTON_COLOR):
    pygame.draw.rect(screen, bg_color, rect)
    pygame.draw.rect(screen, TEXT_COLOR, rect, border_width)
    txt_surf = font.render(text, True, BUTTON_TEXT_COLOR)
    screen.blit(txt_surf, txt_surf.get_rect(center=rect.center))

# ====================== HELPERS ======================
def nim_sum(piles):
    return piles[0] ^ piles[1] ^ piles[2]

def is_losing_position(piles, misere):
    total = sum(piles)
    if total == 0: return False
    if not misere or max(piles) > 1:
        return nim_sum(piles) == 0
    return sum(1 for p in piles if p == 1) % 2 == 1

def find_optimal_move(piles, misere):
    if is_losing_position(piles, misere):
        if sum(piles) == 0: return 0, 0
        return max(range(3), key=lambda x: piles[x]), 1
    for i in range(3):
        for remove in range(1, piles[i] + 1):
            new_piles = piles[:]
            new_piles[i] -= remove
            if sum(new_piles) == 0:
                if not misere: return i, remove
                continue
            if is_losing_position(new_piles, misere):
                return i, remove
    return max(range(3), key=lambda x: piles[x]), 1

def generate_random_winnable_piles(misere=False):
    while True:
        p = [random.randint(1, 21) for _ in range(3)]
        if not is_losing_position(p, misere):
            return p

def draw_stones(center_x, y, count, stone_color, is_hint_pile=False, hint_remove=0, flash_color=None):
    for j in range(count):
        stone_x = center_x + j * STONES_SPACING - (count - 1) * HALF_SPACING
        color = flash_color if (is_hint_pile and flash_color and j >= count - hint_remove) else stone_color
        pygame.draw.circle(screen, color, (int(stone_x), int(y)), STONES_RADIUS)

def draw_binary(center_x, stones_y, pile_idx, count):
    binary = bin(count)[2:].zfill(5)
    text = small_font.render(f"Pile {pile_idx + 1}: {binary}", True, TEXT_COLOR)
    screen.blit(text, (center_x - text.get_width() // 2, stones_y + binary_y_offset))

def flash_hint():
    global hint_active, hint_start_time
    if hint_active and time.time() - hint_start_time < 3:
        return STONE_LOSS if math.sin((time.time() - hint_start_time) * 10) > 0 else STONE_WIN
    hint_active = False
    return None

# ====================== GAME STATE ======================
game_started = False
show_instructions = False
if custom_start:
    pass
else:
    piles = generate_random_winnable_piles(misere_mode)
current_player = 0
message = ""
hint_used = False
hint_active = False
hint_start_time = 0
hint_pile = -1
hint_remove = 0
move_history = []

# ====================== MAIN LOOP ======================
running = True
clock = pygame.time.Clock()
while running:
    total_stones = sum(piles)
    show_restart = (not game_started) or (total_stones == 0)
    show_undo = game_started and total_stones > 0 and current_player == 0 and len(move_history) > 0

    if show_instructions:
        instr_exit_rect.x = (WIDTH - instr_exit_rect.width) // 2
        instr_exit_rect.y = HEIGHT - button_height
    else:
        if not game_started or total_stones == 0:
            total_w = 5 * button_width + 4 * button_spacing
            left_x = (WIDTH - total_w) // 2
            hint_rect.x         = left_x
            mode_rect.x         = hint_rect.right + button_spacing
            instructions_rect.x = mode_rect.right + button_spacing
            restart_rect.x      = instructions_rect.right + button_spacing
            exit_rect.x         = restart_rect.right + button_spacing
            undo_rect.x         = -10000
        else:
            if show_undo:
                total_w = 4 * button_width + 3 * button_spacing
                left_x = (WIDTH - total_w) // 2
                hint_rect.x         = left_x
                undo_rect.x         = hint_rect.right + button_spacing
                instructions_rect.x = undo_rect.right + button_spacing
                exit_rect.x         = instructions_rect.right + button_spacing
                mode_rect.x         = -10000
                restart_rect.x      = -10000
            else:
                total_w = 3 * button_width + 2 * button_spacing
                left_x = (WIDTH - total_w) // 2
                hint_rect.x         = left_x
                instructions_rect.x = hint_rect.right + button_spacing
                exit_rect.x         = instructions_rect.right + button_spacing
                undo_rect.x         = -10000
                mode_rect.x         = -10000
                restart_rect.x      = -10000

    for event in pygame.event.get():
        if event.type == pygame.QUIT or (event.type == pygame.KEYDOWN and event.key == pygame.K_ESCAPE):
            running = False
        elif event.type == pygame.MOUSEBUTTONDOWN:
            mouse_pos = event.pos
            if show_instructions:
                if instr_exit_rect.collidepoint(mouse_pos):
                    show_instructions = False
            else:
                if hint_rect.collidepoint(mouse_pos) and current_player == 0 and total_stones > 0:
                    hint_pile, hint_remove = find_optimal_move(piles, misere_mode)
                    hint_used = True
                    hint_active = True
                    hint_start_time = time.time()
                elif (not game_started or total_stones == 0) and mode_rect.collidepoint(mouse_pos):
                    misere_mode = not misere_mode
                    piles = generate_random_winnable_piles(misere_mode)
                    move_history = []
                    if total_stones == 0:
                        current_player = 0
                        message = ""
                        hint_used = False
                        hint_active = False
                        hint_pile = -1
                        hint_remove = 0
                        game_started = False
                elif instructions_rect.collidepoint(mouse_pos):
                    show_instructions = True
                elif restart_rect.collidepoint(mouse_pos) and show_restart:
                    piles = generate_random_winnable_piles(misere_mode)
                    move_history = []
                    current_player = 0
                    message = ""
                    hint_used = False
                    hint_active = False
                    hint_pile = -1
                    hint_remove = 0
                    game_started = False
                elif undo_rect.collidepoint(mouse_pos) and show_undo and move_history:
                    piles = move_history.pop()
                    current_player = 0
                    message = ""
                    hint_active = False
                    hint_pile = -1
                    hint_remove = 0
                    hint_used = False
                elif exit_rect.collidepoint(mouse_pos):
                    running = False
                elif current_player == 0 and total_stones > 0:
                    mx, my = mouse_pos
                    for i in range(3):
                        y_stones = PILE_STONES_YS[i]
                        count = piles[i]
                        if count == 0: continue
                        pile_top = y_stones - STONES_RADIUS
                        pile_bottom = y_stones + STONES_RADIUS
                        if not (pile_top <= my <= pile_bottom): continue
                        for j in range(count):
                            stone_center_x = PILE_CENTER_X + j * STONES_SPACING - (count - 1) * HALF_SPACING
                            if abs(mx - stone_center_x) <= STONES_RADIUS:
                                remove_count = count - j
                                move_history.append(piles[:])
                                piles[i] -= remove_count
                                game_started = True
                                if sum(piles) == 0:
                                    if misere_mode:
                                        message = "AI Wins!"
                                        if booing_sound: booing_sound.play()
                                    else:
                                        message = "You Win!" if not hint_used else "You won, but you needed a hint!"
                                        if applause_sound: applause_sound.play()
                                    current_player = -1
                                else:
                                    current_player = 1
                                break
                        else:
                            continue
                        break

    if show_instructions:
        screen.fill(BG_COLOR)
        instr_title = font.render("Instructions", True, TEXT_COLOR)
        screen.blit(instr_title, (WIDTH // 2 - instr_title.get_width() // 2, title_y))

        instructions_lines = [
            "Nim is a classic impartial two-player game with three piles of stones.",
            "",
            "How to play:",
            " • Click any stone in a pile → remove that stone and all to its right.",
            " • Green = winning position   Red = losing position",
            " • Hint flashes optimal move   Undo reverts your last move",
            "",
            "Standard Mode: last stone wins",
            "Misère Mode: last stone loses",
            "",
            "AI is perfect. Sounds are embedded.",
            "One single file — easy to share!"
        ]

        y = title_y + font_size + int(50 * s)
        for line in instructions_lines:
            if line.strip():
                line_text = small_font.render(line, True, TEXT_COLOR)
                screen.blit(line_text, (WIDTH // 2 - line_text.get_width() // 2, y))
            y += int(small_font_size * 1.15)

        draw_button(instr_exit_rect, "Exit")
        pygame.display.flip()
        clock.tick(60)
        continue

    # AI turn
    if current_player == 1 and sum(piles) > 0:
        pile_idx, remove = find_optimal_move(piles, misere_mode)
        piles[pile_idx] -= remove
        if sum(piles) == 0:
            if misere_mode:
                message = "You Win!" if not hint_used else "You won, but you needed a hint!"
                if applause_sound: applause_sound.play()
            else:
                message = "AI Wins!"
                if booing_sound: booing_sound.play()
            current_player = -1
        else:
            current_player = 0

    # Refresh
    total_stones = sum(piles)
    show_restart = (not game_started) or (total_stones == 0)
    show_undo = game_started and total_stones > 0 and current_player == 0 and len(move_history) > 0

    screen.fill(BG_COLOR)

    if total_stones == 0:
        stone_color = STONE_NEUTRAL
    else:
        stone_color = STONE_LOSS if is_losing_position(piles, misere_mode) else STONE_WIN

    current_flash_color = flash_hint() if hint_active else None

    title_text = font.render("Nim Game - Version 1.6.4", True, TEXT_COLOR)
    screen.blit(title_text, (WIDTH // 2 - title_text.get_width() // 2, title_y))

    if game_started and total_stones > 0:
        mode_str = "Misère Mode" if misere_mode else "Standard Mode"
        mode_disp = small_font.render(mode_str, True, TEXT_COLOR)
        screen.blit(mode_disp, (WIDTH // 2 - mode_disp.get_width() // 2, mode_display_y))

    if message:
        msg_text = font.render(message, True, MSG_COLOR)
        screen.blit(msg_text, (WIDTH // 2 - msg_text.get_width() // 2, message_y))

    for i in range(3):
        center_x = PILE_CENTER_X
        y_stones = PILE_STONES_YS[i]
        y_label = y_stones + label_y_offset

        pile_text = font.render(f"Pile {i + 1}: {piles[i]}", True, TEXT_COLOR)
        screen.blit(pile_text, (center_x - pile_text.get_width() // 2, y_label))

        is_hint_pile = (hint_pile == i)
        draw_stones(center_x, y_stones, piles[i], stone_color, is_hint_pile, hint_remove, current_flash_color)

        if binary_mode:
            draw_binary(center_x, y_stones, i, piles[i])

    # Draw buttons with perfect centering
    draw_button(hint_rect, "Hint")

    if not game_started or total_stones == 0:
        mode_color = (200, 50, 50) if misere_mode else BUTTON_COLOR
        draw_button(mode_rect, "Misère" if misere_mode else "Standard", mode_color)

    draw_button(instructions_rect, "Instructions")

    if show_restart:
        draw_button(restart_rect, "Restart")

    draw_button(exit_rect, "Exit")

    if show_undo:
        draw_button(undo_rect, "Undo")

    pygame.display.flip()
    clock.tick(60)

pygame.quit()
sys.exit()
